import React, { type FunctionComponent, isValidElement, useMemo } from "react";
import { Text } from "../../../UI";
import { useLanguage } from "../../../../../";
import type {ILabelProps} from "@lmb-it/kitsconcerto-types";
import {FormControlLabel, FormControlLabelText} from "@lmb-it/kitsconcertomobile";



const Label: FunctionComponent<ILabelProps> = ({ label, className, isFormControl = false, elementId, required }) => {
    const { isRTL } = useLanguage();

    const renderLabel = useMemo(() => {
        if (!label) return "";

        if (isValidElement(label) || typeof label === "string") {
            return label;
        }

        if ("element" in label && label.element) {
            return label.element;
        }

        if ("text" in label && label.text) {
            return label.text;
        }

        return "";
    }, [label]);

    const labelClasses = useMemo(() => {
        const classes: string[] = ["label-position", "w-full"];

        if(className){
            classes.push(className)
        }
        if (typeof label === "string") {
            if (isRTL) {
                classes.push("text-right");
            }
        } else if (label && "placement" in label) {
            if (label.placement === "RL") classes.push("RL");
            if (label.placement === "B") classes.push("B");
            if (label.placement === "T") classes.push("T");
        }

        return classes.join(" ");
    }, [isRTL, label]);

    if (!label) return null;

    if(!isFormControl){
        return(
            <Text
                className={labelClasses}
                // htmlFor does not exist on native; we keep the prop name out completely.
            >
                {renderLabel}
            </Text>
        )
    }
    return(
        <FormControlLabel className={labelClasses} style={{padding:0}}>
            <FormControlLabelText style={{padding:0}}>{renderLabel}</FormControlLabelText>
        </FormControlLabel>
    )
};

export default Label;
